/* com.matjzing.mapper.AdminNoticeMapper.insertAdminNotice */
INSERT INTO NOTICE (
      TITLE
    , CONTENT
    , DISPLAY_DT
    , DISPLAY_YN
    , FIXED_YN
    , VIEW_COUNT
    , USE_YN
    , REGISTER_SEQ
    , REGISTER_IP
    , REGISTRATION_DT
    , UPDATER_SEQ
    , UPDATER_IP
    , UPDATE_DT
) VALUES (
      #{title}
    , #{content}
    , #{displayDt}
    , #{displayYn}
    , #{fixedYn}
    , #{viewCount}
    , TRUE
    , #{registerSeq}
    , #{registerIp}
    , NOW(3)
    , #{updaterSeq}
    , #{updaterIp}
    , NOW(3)
)

mapper.update:
/* com.matjzing.mapper.AdminNoticeMapper.updateAdminNotice */
UPDATE NOTICE SET
      UPDATER_SEQ = #{updaterSeq}
    , UPDATER_IP = #{updaterIp}
    , UPDATE_DT = NOW(3)
    , TITLE = #{title}
    , CONTENT = #{content}
    , DISPLAY_DT = #{displayDt}
    , DISPLAY_YN = #{displayYn}
    , FIXED_YN = #{fixedYn}
    , VIEW_COUNT = #{viewCount}
WHERE NOTICE_SEQ = #{noticeSeq}

/* com.matjzing.mapper.AdminNoticeMapper.deleteAdminNotice */
UPDATE NOTICE SET
      UPDATER_SEQ = #{updaterSeq}
    , UPDATER_IP = #{updaterIp}
    , UPDATE_DT = NOW(3)
    , USE_YN = FALSE
WHERE NOTICE_SEQ = #{noticeSeq}
